create table dirkspzm32.pps_arb_plan_ag_op (
    sid                   varchar2(2 char) not null enable,
    firma_nr              number(6, 0) not null enable,
    arb_plan_id           number(*, 0) not null enable,
    vorgang               number(*, 0) not null enable,
    pos_nr                number(*, 0) not null enable,
    ag_upos               number(*, 0) default 1 not null enable,
    split_min             number(*, 0) default 0 not null enable,
    split_max             number(*, 0) default 0 not null enable,
    ag_o_name1            varchar2(255 char) not null enable,
    ag_o_name2            varchar2(255 char) not null enable,
    info1                 varchar2(255 char),
    info2                 varchar2(255 char),
    info3                 varchar2(255 char),
    vorgangstyp           number(*, 0) default 1 not null enable,
    vorgangsqualifikation varchar2(50 char),
    created_date          date default sysdate not null enable,
    created_login_id      number(*, 0) default - 1 not null enable,
    last_change_date      date,
    last_change_login_id  number(*, 0),
    arb_plan_pos_id       number(*, 0) not null enable,
    ag_alternative        number(*, 0) not null enable
);

alter table dirkspzm32.pps_arb_plan_ag_op
    add constraint pk_pps_arb_plan_ag_op
        primary key ( arb_plan_id,
                      arb_plan_pos_id,
                      ag_alternative,
                      firma_nr,
                      sid )
            using index enable;


